import React from "react";
import { Navigate } from "react-router-dom";

export default function ProtectedRoute({ allowedRole, children }) {
  // get role and id from localStorage (stored during login)
  const role = localStorage.getItem("role");
  const userId = localStorage.getItem("userId");

  // ✅ Safely check if they're present
  if (!role || !userId) {
    console.warn("User not logged in or invalid data in localStorage");
    return <Navigate to="/login" replace />;
  }

  // ✅ If role doesn’t match (e.g., student trying to open mentor page)
  if (allowedRole && role !== allowedRole) {
    console.warn("User role not allowed");
    return <Navigate to="/login" replace />;
  }

  // ✅ Otherwise, render the actual dashboard
  return children;
}
